108→
109→/**
110→ * Get session analytics from the materialized view
111→ */
112→export async function getSessionAnalytics(
113→	orgId: string,
114→	params: {
115→		days?: number;
116→		user_id?: string;
117→		project_path?: string;
118→		repository?: string;
119→		limit?: number;
120→		offset?: number;
121→		sort_by?: "date" | "duration" | "interactions";
122→		sort_order?: "asc" | "desc";
123→	} = {},
124→): Promise<SessionAnalytics[]> {
125→	const {
126→		days = 30,
127→		user_id,
128→		project_path,
129→		repository,
130→		limit = 50,
131→		offset = 0,
132→		sort_by = "date",
133→		sort_order = "desc",
134→	} = params;
135→
136→	const org = escapeString(orgId);
137→	const d = Number(days);
138→	const lim = Number(limit);
139→	const off = Number(offset);
140→
141→	let filters = "";
142→	if (user_id) {
143→		filters += ` AND user_id = '${escapeString(user_id)}'`;
144→	}
145→	if (project_path) {
146→		filters += ` AND project_path = '${escapeString(project_path)}'`;
147→	}
148→	if (repository) {
149→		filters += ` AND repository = '${escapeString(repository)}'`;
150→	}
151→
152→	const sortColumn =
153→		sort_by === "duration"
154→			? "actual_duration_min"
155→			: sort_by === "interactions"
156→				? "total_interactions"
157→				: "sa.session_date";
158→	const sortDirection = sort_order === "asc" ? "ASC" : "DESC";
159→
160→	const query = `
161→    SELECT
162→      session_id,
163→      user_id,
164→      formatDateTime(sa.session_date, '%Y-%m-%d %H:%i:%S') as session_date,
165→      project_path,
166→      organization_id,
167→      repository,
168→      total_interactions,
169→      avg_period_sec,
170→      median_period_sec,
171→      quick_responses,
172→      normal_responses,
173→      long_pauses,
174→      actual_duration_min,
175→      formatDateTime(sa.last_interaction_date, '%Y-%m-%d %H:%i:%S') as last_interaction_date,
176→      total_tokens,
177→      input_tokens,
178→      output_tokens,
179→      git_sha,
180→      git_branch,
181→      has_commit,
182→      subagent_types,
183→      skills,
184→      slash_commands,
185→      session_archetype,
186→      success_score,
187→      error_count,
188→      model_used,
189→      used_plan_mode
190→    FROM rudel.session_analytics sa
191→    WHERE ${buildDateFilter(d, "sa.session_date")}
192→      AND organization_id = '${org}'
193→      ${filters}
194→    ORDER BY ${sortColumn} ${sortDirection}
195→    LIMIT ${lim}
196→    OFFSET ${off}
197→  `;
198→
199→	const raw = await queryClickhouse<SessionAnalyticsRaw>(query);
200→
201→	return raw.map(
202→		(row): SessionAnalytics => ({
203→			session_id: row.session_id,
204→			user_id: row.user_id,
205→			session_date: row.session_date,
206→			project_path: row.project_path,
207→			repository: row.repository || null,
208→			duration_min: row.actual_duration_min,
209→			total_tokens: row.total_tokens,
210→			input_tokens: row.input_tokens,
211→			output_tokens: row.output_tokens,
212→			success_score: row.success_score,
213→			total_interactions: row.total_interactions,
214→			avg_period_sec: row.avg_period_sec,
215→			subagent_types: row.subagent_types,
216→			skills: row.skills,
217→			slash_commands: row.slash_commands,
218→			has_commit: row.has_commit > 0,
219→			session_archetype: row.session_archetype,
220→			model_used: row.model_used,
221→			used_plan_mode: row.used_plan_mode > 0,
222→		}),
223→	);
224→}
225→
226→/**
227→ * Get summary statistics from session analytics
228→ */
229→export async function getSessionAnalyticsSummary(
230→	orgId: string,
231→	params: {
232→		days?: number;
233→		user_id?: string;
234→		project_path?: string;
235→	} = {},
236→): Promise<SessionAnalyticsSummary> {
237→	const { days = 30, user_id, project_path } = params;
238→	const org = escapeString(orgId);
239→	const d = Number(days);
240→
241→	let filters = "";
242→	if (user_id) {
243→		filters += ` AND user_id = '${escapeString(user_id)}'`;
244→	}
245→	if (project_path) {
246→		filters += ` AND project_path = '${escapeString(project_path)}'`;
247→	}
248→
249→	const query = `
250→    WITH totals AS (
251→      SELECT
252→        COUNT(*) as cnt_sessions,
253→        SUM(total_interactions) as sum_interactions,
254→        SUM(quick_responses) as sum_quick_responses,
255→        SUM(long_pauses) as sum_long_pauses,
256→        ifNull(AVG(actual_duration_min), 0) as avg_duration,
257→        ifNull(AVG(total_interactions), 0) as avg_interactions,
258→        ifNull(AVG(avg_period_sec), 0) as avg_response,
259→        ifNull(AVG(median_period_sec), 0) as med_response,
260→        countIf(length(subagent_types) > 0) as cnt_subagents,
261→        countIf(length(skills) > 0) as cnt_skills,
262→        countIf(length(slash_commands) > 0) as cnt_slash
263→      FROM rudel.session_analytics
264→      WHERE ${buildDateFilter(d)}
265→        AND organization_id = '${org}'
266→        ${filters}
267→    )
268→    SELECT
269→      cnt_sessions as total_sessions,
270→      sum_interactions as total_interactions,
271→      ifNull(round(avg_duration, 2), 0) as avg_session_duration_min,
272→      ifNull(round(avg_interactions, 2), 0) as avg_interactions_per_session,
273→      ifNull(round(avg_response, 2), 0) as avg_response_time_sec,
274→      ifNull(round(med_response, 2), 0) as median_response_time_sec,
275→      round(sum_quick_responses * 100.0 / if(sum_interactions > 0, sum_interactions, 1), 2) as quick_response_rate,
276→      round(sum_long_pauses * 100.0 / if(sum_interactions > 0, sum_interactions, 1), 2) as long_pause_rate,
277→      round(cnt_subagents * 100.0 / if(cnt_sessions > 0, cnt_sessions, 1), 2) as subagents_adoption_rate,
278→      round(cnt_skills * 100.0 / if(cnt_sessions > 0, cnt_sessions, 1), 2) as skills_adoption_rate,
279→      round(cnt_slash * 100.0 / if(cnt_sessions > 0, cnt_sessions, 1), 2) as slash_commands_adoption_rate
280→    FROM totals
281→  `;
282→
283→	const results = await queryClickhouse<SessionAnalyticsSummary>(query);
284→
285→	const defaults: SessionAnalyticsSummary = {
286→		total_sessions: 0,
287→		total_interactions: 0,
288→		avg_session_duration_min: 0,
289→		avg_interactions_per_session: 0,
290→		avg_response_time_sec: 0,
291→		median_response_time_sec: 0,
292→		quick_response_rate: 0,
293→		long_pause_rate: 0,
294→		subagents_adoption_rate: 0,
295→		skills_adoption_rate: 0,
296→		slash_commands_adoption_rate: 0,
297→	};
298→
299→	if (results.length === 0) {
300→		return defaults;
301→	}
302→
303→	// Coalesce nulls from ClickHouse (AVG on 0 rows returns null despite ifNull)
304→	const row = results[0] as Record<string, unknown> | undefined;
305→	if (!row) return defaults;
306→	return Object.fromEntries(
307→		Object.entries(defaults).map(([key, def]) => [key, row[key] ?? def]),
308→	) as SessionAnalyticsSummary;
309→}
310→
311→export interface SessionSummaryComparisonPeriod {
312→	total_sessions: number;
313→	avg_session_duration_min: number;
314→	avg_response_time_sec: number;
315→	subagents_adoption_rate: number;
316→	skills_adoption_rate: number;
317→	slash_commands_adoption_rate: number;
318→}
319→
320→/**
321→ * Get session analytics summary with period-over-period comparison
322→ */
323→export async function getSessionAnalyticsSummaryComparison(
324→	orgId: string,
325→	params: {
326→		days?: number;
327→		user_id?: string;
328→		project_path?: string;
329→	} = {},
330→) {
331→	const { days = 7, user_id, project_path } = params;
332→	const org = escapeString(orgId);
333→	const d = Number(days);
334→	const previousDays = d * 2;
335→
336→	let filters = "";
337→	if (user_id) {
338→		filters += ` AND user_id = '${escapeString(user_id)}'`;
339→	}
340→	if (project_path) {
341→		filters += ` AND project_path = '${escapeString(project_path)}'`;
342→	}
343→
344→	const summarySQL = (dateCondition: string) => `
345→    WITH totals AS (
346→      SELECT
347→        COUNT(*) as cnt_sessions,
348→        ifNull(AVG(actual_duration_min), 0) as avg_duration,
349→        ifNull(AVG(avg_period_sec), 0) as avg_response,
350→        countIf(length(subagent_types) > 0) as cnt_subagents,
351→        countIf(length(skills) > 0) as cnt_skills,
352→        countIf(length(slash_commands) > 0) as cnt_slash
353→      FROM rudel.session_analytics
354→      WHERE ${dateCondition}
355→        AND organization_id = '${org}'
356→        ${filters}
357→    )
358→    SELECT
359→      cnt_sessions as total_sessions,
360→      ifNull(round(avg_duration, 2), 0) as avg_session_duration_min,
361→      ifNull(round(avg_response, 2), 0) as avg_response_time_sec,
362→      round(cnt_subagents * 100.0 / if(cnt_sessions > 0, cnt_sessions, 1), 2) as subagents_adoption_rate,
363→      round(cnt_skills * 100.0 / if(cnt_sessions > 0, cnt_sessions, 1), 2) as skills_adoption_rate,
364→      round(cnt_slash * 100.0 / if(cnt_sessions > 0, cnt_sessions, 1), 2) as slash_commands_adoption_rate
365→    FROM totals
366→  `;
367→
368→	const currentQuery = summarySQL(buildDateFilter(d));
369→	const previousQuery = summarySQL(
370→		`session_date >= now64(3) - INTERVAL ${previousDays} DAY AND session_date < now64(3) - INTERVAL ${d} DAY`,
371→	);
372→
373→	const [currentData, previousData] = await Promise.all([
374→		queryClickhouse<SessionSummaryComparisonPeriod>(currentQuery),
375→		queryClickhouse<SessionSummaryComparisonPeriod>(previousQuery),
376→	]);
377→
378→	const defaultPeriod: SessionSummaryComparisonPeriod = {
379→		total_sessions: 0,
380→		avg_session_duration_min: 0,
381→		avg_response_time_sec: 0,
382→		subagents_adoption_rate: 0,
383→		skills_adoption_rate: 0,
384→		slash_commands_adoption_rate: 0,
385→	};
386→
387→	// Coalesce nulls from ClickHouse (AVG on 0 rows returns null despite ifNull)
388→	const coalesce = (
389→		row: SessionSummaryComparisonPeriod | undefined,
390→	): SessionSummaryComparisonPeriod => {
391→		if (!row) return { ...defaultPeriod };
392→		return Object.fromEntries(
393→			Object.entries(defaultPeriod).map(([key, def]) => [
394→				key,
395→				(row as unknown as Record<string, unknown>)[key] ?? def,
396→			]),
397→		) as SessionSummaryComparisonPeriod;
398→	};
399→	const current = coalesce(currentData[0]);
400→	const previous = coalesce(previousData[0]);
401→
402→	const calculateChange = (curr: number, prev: number) => {
403→		if (!prev || prev === 0) return 0;
404→		return ((curr - prev) / prev) * 100;
405→	};
406→
407→	const changes = {
408→		total_sessions: calculateChange(
409→			current.total_sessions || 0,
410→			previous.total_sessions || 0,
411→		),
412→		avg_session_duration_min: calculateChange(
413→			current.avg_session_duration_min || 0,
414→			previous.avg_session_duration_min || 0,
415→		),
416→		avg_response_time_sec: calculateChange(
417→			current.avg_response_time_sec || 0,
418→			previous.avg_response_time_sec || 0,
419→		),
420→	};
421→
422→	return { current, previous, changes };
423→}
