428→export async function getInteractionTimingDistribution(
429→	orgId: string,
430→	params: {
431→		days?: number;
432→		user_id?: string;
433→		project_path?: string;
434→	} = {},
435→): Promise<Array<{ bucket: string; count: number; percentage: number }>> {
436→	const { days = 30, user_id, project_path } = params;
437→	const org = escapeString(orgId);
438→	const d = Number(days);
439→
440→	let filters = "";
441→	if (user_id) {
442→		filters += ` AND user_id = '${escapeString(user_id)}'`;
443→	}
444→	if (project_path) {
445→		filters += ` AND project_path = '${escapeString(project_path)}'`;
446→	}
447→
448→	const query = `
449→    WITH total AS (
450→      SELECT SUM(total_interactions) as total_count
451→      FROM rudel.session_analytics
452→      WHERE ${buildDateFilter(d)}
453→        AND organization_id = '${org}'
454→        ${filters}
455→    )
456→    SELECT
457→      'Instant (< 5s)' as bucket,
458→      SUM(quick_responses) as count,
459→      round(SUM(quick_responses) * 100.0 / (SELECT total_count FROM total), 2) as percentage
460→    FROM rudel.session_analytics
461→    WHERE ${buildDateFilter(d)}
462→      AND organization_id = '${org}'
463→      ${filters}
464→
465→    UNION ALL
466→
467→    SELECT
468→      'Normal (5-60s)' as bucket,
469→      SUM(normal_responses) as count,
470→      round(SUM(normal_responses) * 100.0 / (SELECT total_count FROM total), 2) as percentage
471→    FROM rudel.session_analytics
472→    WHERE ${buildDateFilter(d)}
473→      AND organization_id = '${org}'
474→      ${filters}
475→
476→    UNION ALL
477→
478→    SELECT
479→      'Long Pause (> 5m)' as bucket,
480→      SUM(long_pauses) as count,
481→      round(SUM(long_pauses) * 100.0 / (SELECT total_count FROM total), 2) as percentage
482→    FROM rudel.session_analytics
483→    WHERE ${buildDateFilter(d)}
484→      AND organization_id = '${org}'
485→      ${filters}
486→
487→    ORDER BY count DESC
