135→export async function getROIMetrics(
136→	orgId: string,
137→	days = 7,
138→): Promise<ROIMetrics> {
139→	const org = escapeString(orgId);
140→	const d = Number(days);
141→
142→	const query = `
143→    WITH current_period AS (
144→      SELECT
145→        COUNT(*) as total_sessions,
146→        SUM(input_tokens) as total_input_tokens,
147→        SUM(output_tokens) as total_output_tokens,
148→        SUM(total_tokens) as total_tokens,
149→        SUM(actual_duration_min) / 60.0 as total_hours,
150→        AVG(success_score) as avg_success_score,
151→        COUNT(DISTINCT user_id) as active_developers,
152→        SUM(has_commit) as total_commits,
153→        now64(3) - INTERVAL ${d} DAY as period_start,
154→        now64(3) as period_end
155→      FROM rudel.session_analytics
156→      WHERE ${buildDateFilter(d)}
157→        AND organization_id = '${org}'
158→    ),
159→    previous_period AS (
160→      SELECT
161→        COUNT(*) as total_sessions,
162→        SUM(input_tokens) as total_input_tokens,
163→        SUM(output_tokens) as total_output_tokens,
164→        SUM(has_commit) as total_commits,
165→        now64(3) - INTERVAL ${d * 2} DAY as period_start,
166→        now64(3) - INTERVAL ${d} DAY as period_end
167→      FROM rudel.session_analytics
168→      WHERE session_date >= now64(3) - INTERVAL ${d * 2} DAY
169→        AND session_date < now64(3) - INTERVAL ${d} DAY
170→        AND organization_id = '${org}'
171→    )
172→    SELECT
173→      c.total_sessions,
174→      c.total_input_tokens,
175→      c.total_output_tokens,
176→      c.total_tokens,
177→      c.total_hours,
178→      c.avg_success_score,
179→      c.active_developers,
180→      c.total_commits,
181→      round((c.total_output_tokens / 1000000.0) * ${OUTPUT_PRICE_PER_MILLION} +
182→            (c.total_input_tokens / 1000000.0) * ${INPUT_PRICE_PER_MILLION}, 2) as total_cost,
183→      round((c.total_output_tokens / 1000000.0) * ${OUTPUT_PRICE_PER_MILLION} +
184→            (c.total_input_tokens / 1000000.0) * ${INPUT_PRICE_PER_MILLION}, 4) / c.total_sessions as cost_per_session,
185→      if(c.total_commits > 0,
186→        round((c.total_output_tokens / 1000000.0) * ${OUTPUT_PRICE_PER_MILLION} +
187→              (c.total_input_tokens / 1000000.0) * ${INPUT_PRICE_PER_MILLION}, 4) / c.total_commits,
188→        0) as cost_per_commit,
189→      round((p.total_output_tokens / 1000000.0) * ${OUTPUT_PRICE_PER_MILLION} +
190→            (p.total_input_tokens / 1000000.0) * ${INPUT_PRICE_PER_MILLION}, 2) as prev_total_cost,
191→      round((p.total_output_tokens / 1000000.0) * ${OUTPUT_PRICE_PER_MILLION} +
192→            (p.total_input_tokens / 1000000.0) * ${INPUT_PRICE_PER_MILLION}, 4) / p.total_sessions as prev_cost_per_session,
193→      if(p.total_commits > 0,
194→        round((p.total_output_tokens / 1000000.0) * ${OUTPUT_PRICE_PER_MILLION} +
195→              (p.total_input_tokens / 1000000.0) * ${INPUT_PRICE_PER_MILLION}, 4) / p.total_commits,
196→        0) as prev_cost_per_commit,
197→      p.total_commits as prev_total_commits,
198→      p.total_output_tokens as prev_total_output_tokens,
199→      formatDateTime(c.period_start, '%Y-%m-%d') as current_period_start,
200→      formatDateTime(c.period_end, '%Y-%m-%d') as current_period_end,
201→      formatDateTime(p.period_start, '%Y-%m-%d') as previous_period_start,
202→      formatDateTime(p.period_end, '%Y-%m-%d') as previous_period_end
203→    FROM current_period c
204→    CROSS JOIN previous_period p
205→  `;
206→
207→	const result = await queryClickhouse<ROIMetricsQueryResult>(query);
208→
209→	if (!result || result.length === 0) {
210→		throw new Error("No data available for ROI metrics");
211→	}
212→
213→	const data = result[0] as ROIMetricsQueryResult;
214→
215→	// Calculate percentage changes
216→	const totalCostChangePct =
217→		data.prev_total_cost > 0
218→			? ((data.total_cost - data.prev_total_cost) / data.prev_total_cost) * 100
219→			: 0;
220→
221→	const costPerSessionChangePct =
222→		data.prev_cost_per_session > 0
223→			? ((data.cost_per_session - data.prev_cost_per_session) /
224→					data.prev_cost_per_session) *
225→				100
226→			: 0;
227→
228→	const costPerCommitChangePct =
229→		data.prev_cost_per_commit > 0 && data.cost_per_commit > 0
230→			? ((data.cost_per_commit - data.prev_cost_per_commit) /
231→					data.prev_cost_per_commit) *
232→				100
233→			: 0;
234→
235→	// Calculate productivity improvement
236→	const currentCommitsPerDollar =
237→		data.total_cost > 0 ? data.total_commits / data.total_cost : 0;
238→	const prevCommitsPerDollar =
239→		data.prev_total_cost > 0
240→			? data.prev_total_commits / data.prev_total_cost
241→			: 0;
242→	const productivityImprovementPct =
243→		prevCommitsPerDollar > 0
244→			? ((currentCommitsPerDollar - prevCommitsPerDollar) /
245→					prevCommitsPerDollar) *
246→				100
247→			: 0;
248→
249→	// Token utilization rate (compared to baseline of 10M tokens per week)
250→	const baselineTokensPerWeek = 10_000_000;
251→	const tokenUtilizationRate =
252→		(data.total_tokens / baselineTokensPerWeek) * 100;
253→
254→	// Developer hours saved
255→	const currentLOC =
256→		(data.total_output_tokens * CODE_PERCENTAGE) / TOKENS_PER_LOC;
257→	const previousLOC =
258→		(data.prev_total_output_tokens * CODE_PERCENTAGE) / TOKENS_PER_LOC;
259→
260→	const currentHoursSaved = currentLOC / LOC_PER_HOUR;
261→	const previousHoursSaved = previousLOC / LOC_PER_HOUR;
262→
263→	const currentValueCreated = currentHoursSaved * DEFAULT_DEV_HOURLY_RATE;
264→	const currentDollarValueSaved = currentValueCreated - data.total_cost;
265→
266→	const roiPercentage =
267→		data.total_cost > 0 ? (currentDollarValueSaved / data.total_cost) * 100 : 0;
268→
269→	const devHoursSavedChangePct =
270→		previousHoursSaved > 0
271→			? ((currentHoursSaved - previousHoursSaved) / previousHoursSaved) * 100
272→			: 0;
273→
274→	return {
275→		total_cost: Number(data.total_cost) || 0,
276→		total_cost_change_pct: Number(totalCostChangePct.toFixed(2)),
277→		cost_per_session: Number(data.cost_per_session) || 0,
278→		cost_per_session_change_pct: Number(costPerSessionChangePct.toFixed(2)),
279→		cost_per_commit: Number(data.cost_per_commit) || 0,
280→		cost_per_commit_change_pct: Number(costPerCommitChangePct.toFixed(2)),
281→		total_tokens: Number(data.total_tokens) || 0,
282→		input_tokens: Number(data.total_input_tokens) || 0,
283→		output_tokens: Number(data.total_output_tokens) || 0,
284→		token_utilization_rate: Number(tokenUtilizationRate.toFixed(2)),
285→		total_sessions: Number(data.total_sessions) || 0,
286→		total_commits: Number(data.total_commits) || 0,
287→		total_hours: Number(data.total_hours) || 0,
288→		active_developers: Number(data.active_developers) || 0,
289→		avg_success_score: Number(data.avg_success_score) || 0,
290→		commits_per_dollar: parseFloat(currentCommitsPerDollar.toFixed(2)),
291→		sessions_per_dollar:
292→			data.total_cost > 0
293→				? parseFloat((data.total_sessions / data.total_cost).toFixed(2))
294→				: 0,
295→		productivity_improvement_pct: parseFloat(
296→			productivityImprovementPct.toFixed(2),
297→		),
298→		estimated_loc_generated: parseFloat(currentLOC.toFixed(0)),
299→		dev_hours_saved: parseFloat(currentHoursSaved.toFixed(2)),
300→		dev_hours_saved_change_pct: parseFloat(devHoursSavedChangePct.toFixed(2)),
301→		dollar_value_saved: parseFloat(currentDollarValueSaved.toFixed(2)),
302→		roi_percentage: parseFloat(roiPercentage.toFixed(2)),
303→		current_period_start: data.current_period_start,
304→		current_period_end: data.current_period_end,
305→		previous_period_start: data.previous_period_start,
306→		previous_period_end: data.previous_period_end,
307→	};
308→}
