174→/**
175→ * Get detailed metrics for a specific developer
176→ */
177→export async function getDeveloperDetails(
178→	orgId: string,
179→	userId: string,
180→	days = 30,
181→): Promise<DeveloperDetails | null> {
182→	const org = escapeString(orgId);
183→	const uid = escapeString(userId);
184→	const d = Number(days);
185→
186→	const query = `
187→    WITH current_period AS (
188→      SELECT
189→        user_id,
190→        COUNT(*) as total_sessions,
191→        COUNT(DISTINCT toDate(session_date)) as active_days,
192→        SUM(ifNull(input_tokens, 0) + ifNull(output_tokens, 0)) as total_tokens,
193→        SUM(ifNull(input_tokens, 0)) as input_tokens_sum,
194→        SUM(ifNull(output_tokens, 0)) as output_tokens_sum,
195→        round(SUM(actual_duration_min), 2) as total_duration_min,
196→        round(AVG(actual_duration_min), 2) as avg_session_duration_min,
197→        toString(max(session_date)) as last_active_date,
198→        round(AVG(success_score), 2) as success_rate,
199→        COUNT(DISTINCT project_path) as distinct_projects,
200→        SUM(error_count) as error_count
201→      FROM rudel.session_analytics
202→      WHERE user_id = '${uid}'
203→        AND ${buildDateFilter(d)}
204→        AND organization_id = '${org}'
205→      GROUP BY user_id
206→    ),
207→    previous_period AS (
208→      SELECT
209→        user_id,
210→        round(AVG(success_score), 2) as prev_success_rate
211→      FROM rudel.session_analytics
212→      WHERE user_id = '${uid}'
213→        AND session_date >= now64(3) - INTERVAL ${d * 2} DAY
214→        AND session_date < now64(3) - INTERVAL ${d} DAY
215→        AND organization_id = '${org}'
216→      GROUP BY user_id
217→    )
218→    SELECT
219→      c.user_id,
220→      c.total_sessions,
221→      c.active_days,
222→      c.total_tokens,
223→      c.input_tokens_sum as input_tokens,
224→      c.output_tokens_sum as output_tokens,
225→      c.total_duration_min,
226→      c.avg_session_duration_min,
227→      c.last_active_date,
228→      c.success_rate,
229→      round((c.output_tokens_sum * 0.000015) + (c.input_tokens_sum * 0.000003), 4) as cost,
230→      round(c.success_rate - ifNull(p.prev_success_rate, c.success_rate), 2) as success_rate_trend,
231→      c.distinct_projects,
232→      c.error_count
233→    FROM current_period c
234→    LEFT JOIN previous_period p ON c.user_id = p.user_id
235→  `;
236→
237→	const results = await queryClickhouse<DeveloperDetails>(query);
238→	const [first] = results;
239→	if (!first) return null;
240→
241→	return first;
242→}
