253→		outcome?: "success" | "all";
254→		limit?: number;
255→		offset?: number;
256→		sort_by?: "date" | "duration" | "tokens";
257→		sort_order?: "asc" | "desc";
258→	} = {},
259→): Promise<DeveloperSession[]> {
260→	const {
261→		days = 30,
262→		project_path,
263→		outcome,
264→		limit = 50,
265→		offset = 0,
266→		sort_by = "date",
267→		sort_order = "desc",
268→	} = params;
