270→	const org = escapeString(orgId);
271→	const uid = escapeString(userId);
272→	const d = Number(days);
273→	const lim = Number(limit);
274→	const off = Number(offset);
275→
276→	let filters = "";
277→	if (project_path) {
278→		filters += ` AND project_path = '${escapeString(project_path)}'`;
279→	}
280→	if (outcome === "success") {
281→		filters += ` AND actual_duration_min BETWEEN 5 AND 240`;
282→	}
283→
284→	const sortColumn =
285→		sort_by === "duration"
286→			? "actual_duration_min"
287→			: sort_by === "tokens"
288→				? "total_tokens"
289→				: "session_date";
290→	const sortDirection = sort_order === "asc" ? "ASC" : "DESC";
291→
292→	const query = `
293→    SELECT
294→      session_id,
295→      toString(session_date) as session_date,
296→      project_path,
297→      actual_duration_min as duration_min,
298→      ifNull(input_tokens, 0) as input_tokens,
299→      ifNull(output_tokens, 0) as output_tokens,
300→      ifNull(input_tokens, 0) + ifNull(output_tokens, 0) as total_tokens,
301→      length(subagent_types) > 0 as has_subagents,
302→      length(skills) > 0 as has_skills,
303→      length(slash_commands) > 0 as has_slash_commands,
304→      error_count > 0 as has_errors,
305→      actual_duration_min BETWEEN 5 AND 240 as likely_success
306→    FROM rudel.session_analytics
307→    WHERE user_id = '${uid}'
308→      AND ${buildDateFilter(d)}
309→      AND organization_id = '${org}'
310→      ${filters}
311→    ORDER BY ${sortColumn} ${sortDirection}
312→    LIMIT ${lim}
313→    OFFSET ${off}
314→  `;
315→
316→	const results = await queryClickhouse<DeveloperSession>(query);
317→
318→	return results.map((session) => ({
319→		...session,
