361→/**
362→ * Get errors encountered by a developer
363→ */
364→export async function getDeveloperErrors(
365→	orgId: string,
366→	userId: string,
367→	days = 30,
368→): Promise<DeveloperError[]> {
369→	const org = escapeString(orgId);
370→	const uid = escapeString(userId);
371→	const d = Number(days);
372→
373→	const query = `
374→    WITH error_extracts AS (
375→      SELECT
376→        session_id,
377→        session_date,
378→        CASE
379→          WHEN content LIKE '%OperationFailed%' THEN 'OperationFailed'
380→          WHEN content LIKE '%UnknownError%' THEN 'UnknownError'
381→          WHEN content LIKE '%ORPCError%' THEN 'ORPCError'
382→          WHEN content LIKE '%TimeoutError%' THEN 'TimeoutError'
383→          WHEN content LIKE '%TypeError%' THEN 'TypeError'
384→          WHEN content LIKE '%ReferenceError%' THEN 'ReferenceError'
385→          WHEN content LIKE '%Error:%' OR content LIKE '%error:%' THEN 'GenericError'
386→          ELSE NULL
387→        END as error_pattern
388→      FROM rudel.session_analytics
389→      WHERE user_id = '${uid}'
390→        AND ${buildDateFilter(d)}
391→        AND organization_id = '${org}'
392→        AND (content LIKE '%Error:%' OR content LIKE '%error:%')
393→    )
394→    SELECT
395→      error_pattern,
396→      COUNT(*) as occurrences,
397→      toString(min(session_date)) as first_seen,
398→      toString(max(session_date)) as last_seen,
399→      COUNT(DISTINCT session_id) as sessions_affected
400→    FROM error_extracts
401→    WHERE error_pattern IS NOT NULL
402→    GROUP BY error_pattern
403→    ORDER BY occurrences DESC
404→    LIMIT 20
405→  `;
406→
407→	return queryClickhouse<DeveloperError>(query);
408→}
