467→    FROM rudel.session_analytics
468→    ARRAY JOIN subagent_types as val
469→    WHERE user_id = '${uid}'
470→      AND ${buildDateFilter(d)}
471→      AND organization_id = '${org}'
472→      AND val != ''
473→    GROUP BY val
474→    ORDER BY count DESC
475→    LIMIT 10
476→  `;
477→
478→	const topSkillsQuery = `
479→    SELECT val as name, count() as count
