503→
504→	const [adoptionResults, topSubagents, topSkills, topSlashCommands] =
505→		await Promise.all([
506→			queryClickhouse<{
507→				total_sessions: number;
508→				subagents_sessions: number;
509→				skills_sessions: number;
510→				slash_commands_sessions: number;
511→			}>(adoptionQuery),
512→			queryClickhouse<{ name: string; count: number }>(topSubagentsQuery),
513→			queryClickhouse<{ name: string; count: number }>(topSkillsQuery),
514→			queryClickhouse<{ name: string; count: number }>(topSlashCommandsQuery),
515→		]);
516→
517→	if (adoptionResults.length === 0) {
518→		return {
519→			subagents_adoption_rate: 0,
520→			skills_adoption_rate: 0,
521→			slash_commands_adoption_rate: 0,
