545→				? (stats.skills_sessions / stats.total_sessions) * 100
546→				: 0,
547→		slash_commands_adoption_rate:
548→			stats.total_sessions > 0
549→				? (stats.slash_commands_sessions / stats.total_sessions) * 100
550→				: 0,
