154→        round(AVG(success_score), 2) as success_rate
155→      FROM rudel.session_analytics
156→      WHERE ${buildDateFilter(d)}
157→        AND organization_id = '${org}'
158→        AND repository != ''
159→        ${projectFilter}
160→      GROUP BY repository
161→    ),
162→    previous_period AS (
163→      SELECT
164→        repository,
165→        round(AVG(success_score), 2) as prev_success_rate
166→      FROM rudel.session_analytics
167→      WHERE session_date >= now64(3) - INTERVAL ${d * 2} DAY
168→        AND session_date < now64(3) - INTERVAL ${d} DAY
169→        AND organization_id = '${org}'
170→        AND repository != ''
171→        ${projectFilter}
172→      GROUP BY repository
173→    )
174→    SELECT
175→      c.repository,
176→      c.project_path,
177→      c.sessions,
178→      c.unique_users,
179→      c.total_tokens,
180→      c.input_tokens_sum as input_tokens,
181→      c.output_tokens_sum as output_tokens,
182→      c.total_duration_min,
183→      c.avg_session_duration_min,
184→      c.success_rate,
185→      round((c.output_tokens_sum / 1000000.0) * 15.0 + (c.input_tokens_sum / 1000000.0) * 3.0, 4) as cost,
186→      round(c.success_rate - ifNull(p.prev_success_rate, c.success_rate), 2) as success_rate_trend
187→    FROM current_period c
188→    LEFT JOIN previous_period p ON c.repository = p.repository
189→    ORDER BY c.total_duration_min DESC
190→    LIMIT ${lim}
191→    OFFSET ${off}
192→  `;
193→
194→	const results = await queryClickhouse<ProjectInvestment>(query);
195→
196→	return results.map((project) => ({
197→		...project,
198→		repository: project.repository || null,
199→	}));
200→}
