243→/**
244→ * Get project activity trend over time
245→ */
246→export async function getProjectActivity(
247→	orgId: string,
248→	projectPath: string,
249→	params: { days?: number; granularity?: "day" | "week" | "month" } = {},
250→): Promise<ProjectActivity[]> {
251→	const { days = 30, granularity = "day" } = params;
252→	const org = escapeString(orgId);
253→	const pp = escapeString(projectPath);
254→	const d = Number(days);
255→
256→	let dateGrouping = "toDate(session_date)";
257→	if (granularity === "week") {
258→		dateGrouping = "toMonday(session_date)";
259→	} else if (granularity === "month") {
260→		dateGrouping = "toStartOfMonth(session_date)";
261→	}
262→
263→	const query = `
264→    WITH project_repository AS (
265→      SELECT repository, any(project_path) as project_path
266→      FROM rudel.session_analytics
267→      WHERE project_path = '${pp}'
268→        AND repository != ''
269→        AND organization_id = '${org}'
270→      LIMIT 1
271→    )
272→    SELECT
273→      toString(${dateGrouping}) as date,
274→      pr.project_path,
275→      COUNT(*) as sessions,
276→      COUNT(DISTINCT s.user_id) as unique_users
277→    FROM project_repository pr
278→    INNER JOIN rudel.session_analytics s ON s.repository = pr.repository
279→    WHERE s.${buildDateFilter(d)}
280→      AND s.organization_id = '${org}'
281→    GROUP BY ${dateGrouping}, pr.project_path
282→    ORDER BY date ASC
283→  `;
284→
285→	return queryClickhouse<ProjectActivity>(query);
286→}
