353→      round(AVG(success_score), 2) as success_rate,
354→      round(SUM(actual_duration_min), 2) as total_duration_min
355→    FROM rudel.session_analytics
356→    WHERE repository = (
357→      SELECT repository
358→      FROM rudel.session_analytics
359→      WHERE project_path = '${pp}'
360→        AND repository != ''
361→        AND organization_id = '${org}'
362→      LIMIT 1
363→    )
364→    AND ${buildDateFilter(d)}
365→    AND organization_id = '${org}'
366→  `;
