516→				skills_sessions: number;
517→				slash_commands_sessions: number;
518→			}>(adoptionQuery),
519→			queryClickhouse<{ name: string; count: number }>(topSubagentsQuery),
520→			queryClickhouse<{ name: string; count: number }>(topSkillsQuery),
521→			queryClickhouse<{ name: string; count: number }>(topSlashCommandsQuery),
522→		]);
