570→	days = 30,
571→): Promise<ProjectError[]> {
572→	const org = escapeString(orgId);
573→	const pp = escapeString(projectPath);
574→	const d = Number(days);
575→
576→	const query = `
577→    WITH project_repository AS (
578→      SELECT repository
579→      FROM rudel.session_analytics
580→      WHERE project_path = '${pp}'
581→        AND repository != ''
582→        AND organization_id = '${org}'
583→      LIMIT 1
584→    ),
585→    error_extracts AS (
586→      SELECT
587→        session_id,
588→        user_id,
589→        session_date,
590→        CASE
591→          WHEN content LIKE '%OperationFailed%' THEN 'OperationFailed'
592→          WHEN content LIKE '%UnknownError%' THEN 'UnknownError'
593→          WHEN content LIKE '%ORPCError%' THEN 'ORPCError'
594→          WHEN content LIKE '%TimeoutError%' THEN 'TimeoutError'
595→          WHEN content LIKE '%TypeError%' THEN 'TypeError'
596→          WHEN content LIKE '%ReferenceError%' THEN 'ReferenceError'
597→          WHEN content LIKE '%Error:%' OR content LIKE '%error:%' THEN 'GenericError'
598→          ELSE NULL
599→        END as error_pattern
600→      FROM rudel.session_analytics
601→      WHERE repository = (SELECT repository FROM project_repository)
602→        AND ${buildDateFilter(d)}
603→        AND organization_id = '${org}'
604→        AND (content LIKE '%Error:%' OR content LIKE '%error:%')
605→    )
606→    SELECT
607→      error_pattern,
608→      COUNT(*) as occurrences,
609→      uniq(user_id) as affected_users,
610→      toString(min(session_date)) as first_seen,
611→      toString(max(session_date)) as last_seen
612→    FROM error_extracts
613→    WHERE error_pattern IS NOT NULL
614→    GROUP BY error_pattern
615→    ORDER BY occurrences DESC
616→    LIMIT 20
617→  `;
618→
619→	return queryClickhouse<ProjectError>(query);
620→}
