import {
	buildDateFilter,
	escapeString,
	queryClickhouse,
} from "../clickhouse.js";

export interface ProjectInvestment {
	repository: string | null;
	project_path: string;
	sessions: number;
	unique_users: number;
	total_duration_min: number;
	total_tokens: number;
	success_rate: number;
