345→export async function getSuccessRateMetrics(orgId: string, days = 7) {
346→	const org = escapeString(orgId);
347→	const previousDays = Number(days) * 2;
348→
349→	const currentQuery = `
350→    SELECT
351→      count() as total_sessions,
352→      round(avg(success_score), 1) as avg_success_score,
353→      countIf(success_score >= 70) as high_quality_sessions
354→    FROM rudel.session_analytics
355→    WHERE ${buildDateFilter(days)}
356→      AND organization_id = '${org}'
357→  `;
358→
359→	const previousQuery = `
360→    SELECT
361→      count() as total_sessions,
362→      round(avg(success_score), 1) as avg_success_score,
363→      countIf(success_score >= 70) as high_quality_sessions
364→    FROM rudel.session_analytics
365→    WHERE session_date >= now64(3) - INTERVAL ${previousDays} DAY
366→      AND session_date < now64(3) - INTERVAL ${Number(days)} DAY
367→      AND organization_id = '${org}'
368→  `;
369→
370→	interface SuccessRateStats {
371→		total_sessions: number;
372→		avg_success_score: number;
373→		high_quality_sessions: number;
374→	}
375→
376→	const [currentData, previousData] = await Promise.all([
377→		queryClickhouse<SuccessRateStats>(currentQuery),
378→		queryClickhouse<SuccessRateStats>(previousQuery),
379→	]);
380→
381→	const current: SuccessRateStats = currentData[0] || {
382→		total_sessions: 0,
383→		avg_success_score: 0,
384→		high_quality_sessions: 0,
385→	};
386→
387→	const previous: SuccessRateStats = previousData[0] || {
388→		total_sessions: 0,
389→		avg_success_score: 0,
390→		high_quality_sessions: 0,
391→	};
392→
393→	const currentSuccessRate =
394→		current.total_sessions > 0
395→			? (current.high_quality_sessions / current.total_sessions) * 100
396→			: 0;
397→
398→	const previousSuccessRate =
399→		previous.total_sessions > 0
400→			? (previous.high_quality_sessions / previous.total_sessions) * 100
401→			: 0;
402→
403→	return {
404→		current: {
405→			high_quality_sessions: current.high_quality_sessions,
406→			total_sessions: current.total_sessions,
407→			success_rate: currentSuccessRate,
408→		},
409→		previous: {
410→			high_quality_sessions: previous.high_quality_sessions,
411→			total_sessions: previous.total_sessions,
412→			success_rate: previousSuccessRate,
413→		},
414→		changes: {
415→			success_rate: currentSuccessRate - previousSuccessRate,
416→		},
417→	};
418→}
