106→/**
107→ * Extract project name from path (last segment)
108→ */
109→function extractProjectName(projectPath: string): string {
110→	if (!projectPath) return "";
111→	const segments = projectPath.replace(/\\/g, "/").split("/").filter(Boolean);
112→	return segments[segments.length - 1] || projectPath;
