115→/**
116→ * Get list of all developers with summary stats
117→ */
118→export async function getDeveloperList(
119→	orgId: string,
120→	days = 30,
121→): Promise<DeveloperSummary[]> {
122→	const org = escapeString(orgId);
123→	const d = Number(days);
124→
125→	const query = `
126→    WITH current_period AS (
127→      SELECT
128→        user_id,
129→        COUNT(*) as total_sessions,
130→        COUNT(DISTINCT toDate(session_date)) as active_days,
131→        SUM(ifNull(input_tokens, 0)) as input_tokens_sum,
132→        SUM(ifNull(output_tokens, 0)) as output_tokens_sum,
133→        SUM(ifNull(input_tokens, 0) + ifNull(output_tokens, 0)) as total_tokens,
134→        round(SUM(actual_duration_min), 2) as total_duration_min,
135→        round(AVG(actual_duration_min), 2) as avg_session_duration_min,
136→        toString(max(session_date)) as last_active_date,
137→        round(AVG(success_score), 2) as success_rate
138→      FROM rudel.session_analytics
139→      WHERE ${buildDateFilter(d)}
140→        AND organization_id = '${org}'
141→      GROUP BY user_id
142→    ),
143→    previous_period AS (
144→      SELECT
145→        user_id,
146→        round(AVG(success_score), 2) as prev_success_rate
147→      FROM rudel.session_analytics
148→      WHERE session_date >= now64(3) - INTERVAL ${d * 2} DAY
149→        AND session_date < now64(3) - INTERVAL ${d} DAY
150→        AND organization_id = '${org}'
151→      GROUP BY user_id
152→    )
153→    SELECT
154→      c.user_id,
155→      c.total_sessions,
156→      c.active_days,
157→      c.total_tokens,
158→      c.input_tokens_sum as input_tokens,
159→      c.output_tokens_sum as output_tokens,
160→      c.total_duration_min,
161→      c.avg_session_duration_min,
162→      c.last_active_date,
163→      c.success_rate,
164→      round((c.output_tokens_sum * 0.000015) + (c.input_tokens_sum * 0.000003), 4) as cost,
165→      round(c.success_rate - ifNull(p.prev_success_rate, c.success_rate), 2) as success_rate_trend
166→    FROM current_period c
167→    LEFT JOIN previous_period p ON c.user_id = p.user_id
168→    ORDER BY c.total_sessions DESC
169→  `;
170→
171→	return queryClickhouse<DeveloperSummary>(query);
172→}
