444→export async function getDeveloperFeatureUsage(
445→	orgId: string,
446→	userId: string,
447→	days = 30,
448→): Promise<DeveloperFeatureUsage> {
449→	const org = escapeString(orgId);
450→	const uid = escapeString(userId);
451→	const d = Number(days);
452→
453→	const adoptionQuery = `
454→    SELECT
455→      COUNT(*) as total_sessions,
456→      countIf(length(subagent_types) > 0) as subagents_sessions,
457→      countIf(length(skills) > 0) as skills_sessions,
458→      countIf(length(slash_commands) > 0) as slash_commands_sessions
459→    FROM rudel.session_analytics
460→    WHERE user_id = '${uid}'
461→      AND ${buildDateFilter(d)}
462→      AND organization_id = '${org}'
463→  `;
464→
465→	const topSubagentsQuery = `
466→    SELECT val as name, count() as count
467→    FROM rudel.session_analytics
468→    ARRAY JOIN subagent_types as val
469→    WHERE user_id = '${uid}'
470→      AND ${buildDateFilter(d)}
471→      AND organization_id = '${org}'
472→      AND val != ''
473→    GROUP BY val
474→    ORDER BY count DESC
475→    LIMIT 10
476→  `;
477→
478→	const topSkillsQuery = `
479→    SELECT val as name, count() as count
480→    FROM rudel.session_analytics
481→    ARRAY JOIN skills as val
482→    WHERE user_id = '${uid}'
483→      AND ${buildDateFilter(d)}
484→      AND organization_id = '${org}'
485→      AND val != ''
486→    GROUP BY val
487→    ORDER BY count DESC
488→    LIMIT 10
489→  `;
490→
491→	const topSlashCommandsQuery = `
492→    SELECT val as name, count() as count
493→    FROM rudel.session_analytics
494→    ARRAY JOIN slash_commands as val
495→    WHERE user_id = '${uid}'
496→      AND ${buildDateFilter(d)}
497→      AND organization_id = '${org}'
498→      AND val != ''
499→    GROUP BY val
500→    ORDER BY count DESC
501→    LIMIT 10
502→  `;
503→
504→	const [adoptionResults, topSubagents, topSkills, topSlashCommands] =
505→		await Promise.all([
506→			queryClickhouse<{
507→				total_sessions: number;
508→				subagents_sessions: number;
509→				skills_sessions: number;
510→				slash_commands_sessions: number;
511→			}>(adoptionQuery),
512→			queryClickhouse<{ name: string; count: number }>(topSubagentsQuery),
513→			queryClickhouse<{ name: string; count: number }>(topSkillsQuery),
514→			queryClickhouse<{ name: string; count: number }>(topSlashCommandsQuery),
515→		]);
516→
517→	if (adoptionResults.length === 0) {
518→		return {
519→			subagents_adoption_rate: 0,
520→			skills_adoption_rate: 0,
521→			slash_commands_adoption_rate: 0,
522→			top_subagents: [],
523→			top_skills: [],
524→			top_slash_commands: [],
525→		};
526→	}
527→
528→	const [stats] = adoptionResults;
529→	if (!stats)
530→		return {
531→			subagents_adoption_rate: 0,
532→			skills_adoption_rate: 0,
533→			slash_commands_adoption_rate: 0,
534→			top_subagents: [],
535→			top_skills: [],
536→			top_slash_commands: [],
537→		};
538→	return {
539→		subagents_adoption_rate:
540→			stats.total_sessions > 0
541→				? (stats.subagents_sessions / stats.total_sessions) * 100
542→				: 0,
543→		skills_adoption_rate:
544→			stats.total_sessions > 0
545→				? (stats.skills_sessions / stats.total_sessions) * 100
546→				: 0,
547→		slash_commands_adoption_rate:
548→			stats.total_sessions > 0
549→				? (stats.slash_commands_sessions / stats.total_sessions) * 100
550→				: 0,
551→		top_subagents: topSubagents,
552→		top_skills: topSkills,
553→		top_slash_commands: topSlashCommands,
554→	};
555→}
