 31→/**
 32→ * Get learnings feed from compound:feedback sessions
 33→ */
 34→export async function getLearningsFeed(
 35→	orgId: string,
 36→	params: {
 37→		days?: number;
 38→		user_id?: string;
 39→		project_path?: string;
 40→		limit?: number;
 41→		offset?: number;
 42→	} = {},
 43→): Promise<LearningEntry[]> {
 44→	const { days = 30, user_id, project_path, limit = 50, offset = 0 } = params;
 45→
 46→	const org = escapeString(orgId);
 47→	const d = Number(days);
 48→	const lim = Number(limit);
 49→	const off = Number(offset);
 50→
 51→	let filters = `last_interaction_date >= now64(3) - INTERVAL ${d} DAY
 52→    AND has(slash_commands, 'compound:feedback')
 53→    AND organization_id = '${org}'`;
 54→
 55→	if (user_id) {
 56→		filters += `\n    AND user_id = '${escapeString(user_id)}'`;
 57→	}
 58→	if (project_path) {
 59→		filters += `\n    AND project_path = '${escapeString(project_path)}'`;
 60→	}
 61→
 62→	const query = `
 63→    WITH
 64→      feedback_data AS (
 65→        SELECT
 66→          session_id,
 67→          user_id,
 68→          last_interaction_date,
 69→          project_path,
 70→          organization_id,
 71→          repository,
 72→          subagents,
 73→          skills,
 74→          slash_commands,
 75→          content
 76→        FROM rudel.session_analytics
 77→        WHERE ${filters}
 78→      )
 79→    SELECT
 80→      session_id,
 81→      user_id,
 82→      formatDateTime(last_interaction_date, '%Y-%m-%dT%H:%i:%SZ') as created_at,
 83→      'feedback' as type,
 84→      if(
 85→        position(content, '<command-name>/compound:feedback</command-name>') > 0
 86→        AND position(content, '<command-args>', position(content, '<command-name>/compound:feedback</command-name>')) > 0
 87→        AND position(content, '</command-args>', position(content, '<command-name>/compound:feedback</command-name>')) > 0,
 88→        trimBoth(
 89→          substring(
 90→            content,
 91→            position(content, '<command-args>', position(content, '<command-name>/compound:feedback</command-name>')) + 14,
 92→            least(
 93→              position(content, '</command-args>', position(content, '<command-name>/compound:feedback</command-name>'))
 94→              - position(content, '<command-args>', position(content, '<command-name>/compound:feedback</command-name>'))
 95→              - 14,
 96→              5000
 97→            )
 98→          )
 99→        ),
100→        concat('Feedback session in ', if(repository != '', repository, project_path))
101→      ) as content,
102→      'project' as scope,
103→      [] as tags,
104→      project_path,
105→      organization_id,
106→      repository,
107→      mapKeys(subagents) as subagents,
108→      skills,
109→      arrayFilter(x -> x != 'compound:feedback', slash_commands) as other_commands
110→    FROM feedback_data
111→    ORDER BY last_interaction_date DESC
112→    LIMIT ${lim}
113→    OFFSET ${off}
114→  `;
115→
116→	return queryClickhouse<LearningEntry>(query);
117→}
