223→/**
224→ * Get learnings trend over time with splits by user_id or repository
225→ */
226→export async function getLearningsTrend(
227→	orgId: string,
228→	params: {
229→		days?: number;
230→		split_by: "user_id" | "repository";
231→	},
232→): Promise<LearningsTrendDataPoint[]> {
233→	const { days = 30, split_by } = params;
234→	const org = escapeString(orgId);
235→	const d = Number(days);
236→
237→	const splitColumn =
238→		split_by === "repository"
239→			? "if(repository != '', repository, 'Unknown')"
240→			: "user_id";
241→
242→	const query = `
243→    SELECT
244→      toDate(last_interaction_date) as date,
245→      ${splitColumn} as split_key,
246→      count() as count
247→    FROM rudel.session_analytics
248→    WHERE last_interaction_date >= now64(3) - INTERVAL ${d} DAY
249→      AND has(slash_commands, 'compound:feedback')
250→      AND organization_id = '${org}'
251→    GROUP BY date, split_key
252→    ORDER BY date ASC, split_key ASC
253→  `;
254→
255→	const rawData = await queryClickhouse<{
256→		date: string;
257→		split_key: string;
258→		count: number;
259→	}>(query);
260→
261→	// Transform data into chart-friendly format
262→	const dataByDate = new Map<string, Record<string, number>>();
263→	const allSplitKeys = new Set<string>();
264→
265→	rawData.forEach((row) => {
266→		if (!dataByDate.has(row.date)) {
267→			dataByDate.set(row.date, {});
268→		}
269→		const entry = dataByDate.get(row.date);
270→		if (entry) entry[row.split_key] = row.count;
271→		allSplitKeys.add(row.split_key);
272→	});
273→
274→	const chartData: LearningsTrendDataPoint[] = Array.from(dataByDate.entries())
275→		.map(([date, counts]) => {
276→			const dataPoint: LearningsTrendDataPoint = { date };
277→			allSplitKeys.forEach((key) => {
278→				dataPoint[key] = counts[key] || 0;
279→			});
280→			return dataPoint;
281→		})
282→		.sort((a, b) => (a.date as string).localeCompare(b.date as string));
283→
284→	return chartData;
285→}
