  7→export interface UserMapping {
  8→	user_id: string;
  9→	username: string;
 10→	session_count: number;
 11→}
 12→
 13→/**
 14→ * Extract username from project path
 15→ * Pattern: /Users/{username}/... or /home/{username}/...
 16→ */
 17→function extractUsernameFromPath(projectPath: string): string | null {
 18→	const match = projectPath.match(/^\/(?:Users|home)\/([^/]+)\//);
 19→	return match ? (match[1] ?? null) : null;
 20→}
 21→
 22→/**
 23→ * Get user ID to username mappings by extracting usernames from project paths
 24→ */
 25→export async function getUserMappings(
 26→	orgId: string,
 27→	days = 30,
 28→): Promise<UserMapping[]> {
 29→	const org = escapeString(orgId);
 30→	const dateFilter = buildDateFilter(days);
 31→
 32→	const query = `
 33→    SELECT
 34→      user_id,
 35→      project_path,
 36→      count() as sessions
 37→    FROM rudel.session_analytics
 38→    WHERE ${dateFilter}
 39→      AND organization_id = '${org}'
 40→    GROUP BY user_id, project_path
 41→    ORDER BY user_id, sessions DESC
 42→  `;
 43→
 44→	const results = await queryClickhouse<{
 45→		user_id: string;
 46→		project_path: string;
 47→		sessions: number;
 48→	}>(query);
 49→
 50→	// Group by user_id and extract the most common username
 51→	const userMap = new Map<
 52→		string,
 53→		{ username: string | null; totalSessions: number }
 54→	>();
 55→
 56→	for (const row of results) {
 57→		const username = extractUsernameFromPath(row.project_path);
 58→
 59→		if (!userMap.has(row.user_id)) {
 60→			userMap.set(row.user_id, { username, totalSessions: row.sessions });
 61→		} else {
 62→			const existing = userMap.get(row.user_id);
 63→			if (!existing) continue;
 64→			if (username && row.sessions > existing.totalSessions) {
 65→				existing.username = username;
 66→				existing.totalSessions = row.sessions;
 67→			}
 68→		}
 69→	}
 70→
 71→	const mappings: UserMapping[] = [];
 72→	for (const [user_id, data] of userMap.entries()) {
 73→		if (data.username) {
 74→			mappings.push({
 75→				user_id,
 76→				username: data.username,
 77→				session_count: data.totalSessions,
 78→			});
 79→		}
 80→	}
 81→
 82→	return mappings.sort((a, b) => b.session_count - a.session_count);
 83→}
