 85→/**
 86→ * Get a single user mapping by user_id
 87→ */
 88→export async function getUserMapping(
 89→	orgId: string,
 90→	userId: string,
 91→	days = 30,
 92→): Promise<UserMapping | null> {
 93→	const org = escapeString(orgId);
 94→	const uid = escapeString(userId);
 95→	const dateFilter = buildDateFilter(days);
 96→
 97→	const query = `
 98→    SELECT
 99→      user_id,
100→      project_path,
101→      count() as sessions
102→    FROM rudel.session_analytics
103→    WHERE ${dateFilter}
104→      AND organization_id = '${org}'
105→      AND user_id = '${uid}'
106→    GROUP BY user_id, project_path
107→    ORDER BY sessions DESC
108→    LIMIT 1
109→  `;
110→
111→	const results = await queryClickhouse<{
112→		user_id: string;
113→		project_path: string;
114→		sessions: number;
115→	}>(query);
116→
117→	const [row] = results;
118→	if (!row) {
119→		return null;
120→	}
121→	const username = extractUsernameFromPath(row.project_path);
122→
123→	if (!username) {
124→		return null;
125→	}
126→
127→	return {
128→		user_id: row.user_id,
129→		username,
130→		session_count: row.sessions,
131→	};
132→}
